import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test
import org.junit.jupiter.params.ParameterizedTest
import org.junit.jupiter.params.provider.ValueSource

/**
 * Tests for Nordic characters in package names
 * Related to: https://github.com/pinterest/ktlint/issues/1761
 */
class PackageNameRuleNordicCharsTest {
    private val packageNameRuleAssertThat = assertThatRule { PackageNameRule() }

    @ParameterizedTest(name = "Nordic chars in package: {0}")
    @ValueSource(
        strings = [
            "føø",
            "foo.føø",
            "bår",
            "foo.bår",
            "tæst",
            "foo.tæst",
            "æøå",
            "foo.æøå",
            "höst",
            "foo.höst",
            "grön",
            "foo.grön",
            "blå",
            "foo.blå",
        ],
    )
    fun `Given a package name containing Nordic characters then do not emit`(packageName: String) {
        val code =
            """
            package $packageName
            """.trimIndent()
        packageNameRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a multi-level package name with Nordic characters then do not emit`() {
        val code =
            """
            package føø.bår.tæst
            """.trimIndent()
        packageNameRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a package name with mixed ASCII and Nordic characters then do not emit`() {
        val code =
            """
            package com.example.føø
            """.trimIndent()
        packageNameRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a package name with numbers and Nordic characters then do not emit`() {
        val code =
            """
            package foo2.bår3
            """.trimIndent()
        packageNameRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

